var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`꼭 당신이 가야만 하는 건가요?`,JPN:`どうしてもあなたが行かないとダメなんですか？`,ENG:`Do they really need you to go?`,TWN:`非你不可嗎？`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`오랫동안 준비해온 일이야. 이제 와서 나 혼자 빠질 수는 없어.`,JPN:`長い間準備してきたことだ。今更私だけ行かないわけにはいかない。`,ENG:`We've been preparing for this for a long time. I can't back out now.`,TWN:`這件事已經準備許久，我無法現在才說要退出。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`돌아오려면… 얼마나 걸릴까요?`,JPN:`帰って来るまで……どのくらいかかるんでしょう？`,ENG:`When... will you be back home?`,TWN:`你這一趟去…多久才會回來？`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`정확한 예정은 없지만, 그리 오래 걸리진 않을 거야.`,JPN:`決まった日程はないが、そう長くはかからないはずだ。`,ENG:`I don't know for sure, but it won't take long.`,TWN:`還不確定，但應該不會太久。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`제발 무사해야 돼요.`,JPN:`どうか無事でありますように。`,ENG:`Please be safe.`,TWN:`你一定要平安回來。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`당신도 부디 무사히 지내고 있어줘.`,JPN:`あなたもどうか無事でいてくれ。`,ENG:`You too, my love.`,TWN:`這段時間你也要照顧好自己。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`잠깐만요.`,JPN:`お待ちください。`,ENG:`Wait!`,TWN:`等等。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`…떠나기 전에 태어날 아이 이름이라도 지어주고 가요.`,JPN:`……出発する前に、生まれてくる子の名前だけでも付けて行ってください。`,ENG:`Before you leave... I want you to name our baby.`,TWN:`離開之前……先替我肚子裡的寶寶取個名字吧。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:null,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:`아직 남자인지 여자인지도 모르잖아.`,JPN:`まだ男か女かもわからないじゃないか。`,ENG:`We don't even know if it's a boy or a girl yet.`,TWN:`都還不知道是男生還女生呢。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:null,text:{KOREA:`기다려줘. 늦지 않게 돌아올 테니까.`,JPN:`待っていておくれ。あまり遅くならないように頑張るから。`,ENG:`Wait for me together. I'll be back as soon as I can.`,TWN:`你跟孩子一起等我，我很快就回來。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`비비안.`,JPN:`ビビアン。`,ENG:`"Vivian".`,TWN:`薇薇安。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`당신이 돌아오기 전에 아이가 태어난다면… 비비안이라고 불러줄게요.`,JPN:`あなたが帰ってくる前にこの子が生まれたら……ビビアンと呼んであげようと思います。`,ENG:`If I give birth before you return... I will name our baby Vivian.`,TWN:`如果孩子在你回來之前出生的話…… 我會叫孩子薇薇安。`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:null,text:{KOREA:`또 혼자 그루터기에 앉아 사색하고 있었나?`,JPN:`また一人で切り株に座って考え込んでいたのか？`,ENG:`Daydreaming alone on that stump again?`,TWN:`又一個人坐在樹上思考嗎？`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`일어나려던 참입니다, 장교님.`,JPN:`もう行こうと思っていたところでした、将校。`,ENG:`I was just about to get up, Officer Rashford.`,TWN:`我正要起來呢，軍官。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_LAUGH`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`VIVIEN_OPR_NULL_NULL`,text:{KOREA:`…난 이곳 부대의 기술교관이다. 더 이상 그런 존칭은 하지 않아도 돼.`,JPN:`……私はこの部隊の技術教官だ。もうそんな敬称はいらない。`,ENG:`…I'm the Technical Instructor of your unit. You don't have to put "Officer" in front of my name anymore.`,TWN:`……我是這個部隊的技術教官，已經不再使用那個稱號。`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_SURPRISE`}}}},{id:`L32_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`그래, 비비안.`,JPN:`わかった、ビビアン。`,ENG:`Very well, Vivian.`,TWN:`好，薇薇安。`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`VIVIEN_OPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_LAUGH`}}}}];export{e as default};